type AnyComponent = React.ComponentType<Record<string, unknown>>;

class ThreeBoundary extends React.Component<
  { name: string; children?: React.ReactNode },
  { failed: boolean }
> {
  state = { failed: false };
  static getDerivedStateFromError() {
    return { failed: true };
  }
  render() {
    if (this.state.failed) {
      return React.createElement(
        'div',
        {
          'data-testid': 'three-unavailable',
          style: { padding: 16, fontSize: 13, lineHeight: 1.5, opacity: 0.7 },
        },
        `3D pattern "${this.props.name}" requires three.js. Install the optional peers ` +
          'three + @react-three/fiber + @react-three/drei (matching the host React major) to render it.',
      );
    }
    return this.props.children;
  }
}

function lazyThree(
  name: string,
  loader: () => Promise<Record<string, unknown>>,
): AnyComponent {
  const Lazy = React.lazy(() =>
    loader().then(m => {
      const Resolved = m[name] as unknown as AnyComponent | undefined;
      if (!Resolved) {
        throw new Error(
          `[@almadar/ui] 3D component "${name}" was not found in the three subpath bundle.`,
        );
      }
      return { default: Resolved };
    }),
  );
  function ThreeWrapper(props: Record<string, unknown>) {
    return React.createElement(
      ThreeBoundary,
      { name },
      React.createElement(
        React.Suspense,
        { fallback: null },
        React.createElement(Lazy, props),
      ),
    );
  }
  ThreeWrapper.displayName = `Lazy(${name})`;
  return ThreeWrapper;
}

